#include <sys/mount.h>

// POSIX mount() system call
int mount(const char *source, const char *target,
          const char *filesystemtype, unsigned long mountflags,
          const void *data);

// Example usage in C program
int main() {
    // Mount a USB drive
    int result = mount("/dev/sdb1", 
                      "/mnt/usb",
                      "vfat",
                      MS_MGC_VAL | MS_RDONLY,
                      NULL);

    if (result == -1) {
        perror("Mount failed");
        return 1;
    }

    printf("Mount successful\n");

    // Later, unmount
    umount2("/mnt/usb", MNT_FORCE);

    return 0;
}

// Mount flags (from sys/mount.h):
// MS_RDONLY   - Read-only mount
// MS_NOSUID   - Ignore suid/sgid bits
// MS_NODEV    - No device files
// MS_NOEXEC   - No execution of programs
// MS_REMOUNT  - Remount with new options
// MS_BIND     - Bind mount operation
